document.addEventListener("DOMContentLoaded",()=>{const n={root:null,rootMargin:"0px",threshold:.1},o=new IntersectionObserver((e,s)=>{e.forEach(t=>{t.isIntersecting&&(t.target.classList.add("visible"),s.unobserve(t.target))})},n);document.querySelectorAll(".fade-in-up").forEach(e=>o.observe(e))});
